mapper.select:
SELECT * FROM (
SELECT
d.DOG_NUMBER, d.DOG_NAME, d.DOG_BREED, d.DOG_IMG_PATH,
/* ABS(사용자 점수 - 유기견 점수)의 합계가 낮을수록 나랑 잘 맞는 강아지 */
(ABS(m.DOG_ACTIVITY - d.DOG_ACTIVITY) +
ABS(m.DOG_SOCIALITY - d.DOG_SOCIALITY) +
ABS(m.DOG_INDEPENDENCE - d.DOG_INDEPENDENCE) +
ABS(m.DOG_BARKING - d.DOG_BARKING) +
ABS(m.DOG_GROOMING - d.DOG_GROOMING)) AS DISTANCE
FROM TBL_DOG_ARCHIVE d, DDD_MATCH_RESULT m
WHERE m.USER_NUMBER = #{userNumber}
/* 사용자가 방금 진행한 가장 최근 설문 결과를 기준으로 비교 */
AND m.RESULT_NUMBER = (
SELECT MAX(RESULT_NUMBER) FROM DDD_MATCH_RESULT WHERE USER_NUMBER =
#{userNumber}
)
ORDER BY DISTANCE ASC, d.DOG_NUMBER DESC
)
WHERE ROWNUM <= 8

mapper.delete:
DELETE FROM
DDD_MATCH_RESULT
WHERE RESULT_NUMBER = (
SELECT MIN(RESULT_NUMBER) FROM DDD_MATCH_RESULT WHERE USER_NUMBER =
#{userNumber}
)
